1тЖТimport React, { useState, useEffect, useRef } from 'react';
2тЖТimport { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
3тЖТimport Login from './components/Login';
4тЖТimport Dashboard from './components/Dashboard';
5тЖТimport AdminPanel from './components/AdminPanel';
6тЖТimport MasterPanel from './components/MasterPanel';
7тЖТimport NazoratchiPanel from './components/NazoratchiPanel';
8тЖТimport UsersPanel from './components/UsersPanel';
9тЖТimport ReportsPanel from './components/ReportsPanel';
10тЖТimport MechanicPanel from './components/MechanicPanel';
11тЖТimport AsnovaPanel from './components/AsnovaPanel';
12тЖТimport Sidebar from './components/Sidebar';
13тЖТ
14тЖТconst SplashScreen = ({ onDone }) => {
15тЖТ  const [fadeOut, setFadeOut] = useState(false);
16тЖТ  const [progress, setProgress] = useState(0);
17тЖТ
18тЖТ  useEffect(() => {
19тЖТ    const interval = setInterval(() => {
20тЖТ      setProgress(prev => {
21тЖТ        if (prev >= 100) {
22тЖТ          clearInterval(interval);
23тЖТ          return 100;
24тЖТ        }
25тЖТ        return prev + 2;
26тЖТ      });
27тЖТ    }, 50);
28тЖТ
29тЖТ    const timer = setTimeout(() => {
30тЖТ      setFadeOut(true);
31тЖТ      setTimeout(() => onDone(), 600);
32тЖТ    }, 3000);
33тЖТ
34тЖТ    return () => {
35тЖТ      clearInterval(interval);
36тЖТ      clearTimeout(timer);
37тЖТ    };
38тЖТ  }, [onDone]);
39тЖТ
40тЖТ  return (
41тЖТ    <div className={`splash-screen ${fadeOut ? 'splash-fade-out' : ''}`}>
42тЖТ      <div className="splash-content">
43тЖТ        <div className="splash-logo">
44тЖТ          <div className="splash-logo-ring"></div>
45тЖТ          <div className="splash-logo-inner">
46тЖТ            <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#00d2ff" strokeWidth="1.5">
47тЖТ              <path d="M12 2L2 7l10 5 10-5-10-5z"/>
48тЖТ              <path d="M2 17l10 5 10-5"/>
49тЖТ              <path d="M2 12l10 5 10-5"/>
50тЖТ            </svg>
51тЖТ          </div>
52тЖТ        </div>
53тЖТ        <h1 className="splash-title">FazoLuxe</h1>
54тЖТ        <p className="splash-subtitle">Industrial Monitoring System</p>
55тЖТ        <div className="splash-progress">
56тЖТ          <div className="splash-progress-bar" style={{ width: `${progress}%` }}></div>
57тЖТ        </div>
58тЖТ        <p className="splash-loading">Yuklanmoqda...</p>
59тЖТ      </div>
60тЖТ    </div>
61тЖТ  );
62тЖТ};
63тЖТ
64тЖТfunction App() {
65тЖТ  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')) || null);
66тЖТ  const [activeTab, setActiveTab] = useState('dashboard');
67тЖТ  const [showSplash, setShowSplash] = useState(true);
68тЖТ
69тЖТ  const handleLogin = (userData) => {
70тЖТ    localStorage.setItem('user', JSON.stringify(userData));
71тЖТ    setUser(userData);
72тЖТ  };
73тЖТ
74тЖТ  const handleLogout = () => {
75тЖТ    localStorage.removeItem('user');
76тЖТ    localStorage.removeItem('token');
77тЖТ    setUser(null);
78тЖТ    setActiveTab('dashboard');
79тЖТ  };
80тЖТ
81тЖТ  const renderContent = () => {
82тЖТ    switch (activeTab) {
83тЖТ      case 'dashboard': return <Dashboard user={user} />;
84тЖТ      case 'reports': return <ReportsPanel user={user} />;
85тЖТ      case 'mechanic': return <MechanicPanel user={user} />;
86тЖТ      case 'admin': return <AdminPanel user={user} />;
87тЖТ      case 'master': return <MasterPanel user={user} />;
88тЖТ      case 'nazoratchi': return <NazoratchiPanel user={user} />;
89тЖТ      case 'users': return <UsersPanel user={user} />;
90тЖТ      case 'asnova': return <AsnovaPanel user={user} />;
91тЖТ      default: return <Dashboard user={user} />;
92тЖТ    }
93тЖТ  };
94тЖТ
95тЖТ  if (showSplash) {
96тЖТ    return <SplashScreen onDone={() => setShowSplash(false)} />;
97тЖТ  }
98тЖТ
99тЖТ  return (
100тЖТ    <Router>
101тЖТ      <Routes>
102тЖТ        <Route path="/login" element={!user ? <Login onLogin={handleLogin} /> : <Navigate to="/" />} />
103тЖТ        <Route path="/*" element={
104тЖТ          user ? (
105тЖТ            <div className="app-container app-appear">
106тЖТ              <Sidebar user={user} activeTab={activeTab} onTabChange={setActiveTab} onLogout={handleLogout} />
107тЖТ              <div className="main-content">
108тЖТ                {renderContent()}
109тЖТ              </div>
110тЖТ            </div>
111тЖТ          ) : (
112тЖТ            <Navigate to="/login" />
113тЖТ          )
114тЖТ        } />
115тЖТ      </Routes>
116тЖТ    </Router>
117тЖТ  );
118тЖТ}
119тЖТ
120тЖТexport default App;
EOF
